    10→## 1. LOD System Implementation
    11→
    12→### HYPOTHESIS
    13→The canvas implements a 3-tier Level of Detail (LOD) system with smooth crossfade transitions between layers.
    14→
    15→### EVIDENCE
    16→
    17→**File:** `apps/canvas/src/canvas/InfiniteCanvas.tsx:70-137`
    18→
    19→```typescript
    20→// LOD Thresholds
    21→const LOD_THRESHOLDS = {
    22→  macroToMeso: 0.5,  // Below 0.5 = MACRO
    23→  mesoToMicro: 2.0,  // Above 2.0 = MICRO
    24→};
    25→
    26→// Size of blend zone around each threshold (+-this value)
    27→const BLEND_ZONE_SIZE = 0.15;
    28→
    29→/**
    30→ * Calculate layer opacities for smooth LOD transitions
    31→ */
    32→function calculateLayerOpacities(zoom: number): {
    33→  macro: number;
    34→  meso: number;
    35→  micro: number;
    36→} {
    37→  const { macroToMeso, mesoToMicro } = LOD_THRESHOLDS;
    38→
    39→  // Define blend zone boundaries
    40→  const macroEnd = macroToMeso - BLEND_ZONE_SIZE; // 0.35
    41→  const mesoStart = macroToMeso + BLEND_ZONE_SIZE; // 0.65
    42→  const mesoEnd = mesoToMicro - BLEND_ZONE_SIZE; // 1.85
    43→  const microStart = mesoToMicro + BLEND_ZONE_SIZE; // 2.15
    44→
    45→  let macro = 0;
    46→  let meso = 0;
    47→  let micro = 0;
    48→
    49→  // MACRO opacity: 1 below macroEnd, fade to 0 through blend zone
    50→  if (zoom <= macroEnd) {
    51→    macro = 1;
    52→  } else if (zoom < mesoStart) {
    53→    const t = (zoom - macroEnd) / (mesoStart - macroEnd);
    54→    macro = 1 - t;
    55→  }
    56→
    57→  // MESO opacity: fade in, full, fade out
    58→  if (zoom < macroEnd) {
    59→    meso = 0;
    60→  } else if (zoom < mesoStart) {
    61→    const t = (zoom - macroEnd) / (mesoStart - macroEnd);
    62→    meso = t;
    63→  } else if (zoom <= mesoEnd) {
    64→    meso = 1;
    65→  } else if (zoom < microStart) {
    66→    const t = (zoom - mesoEnd) / (microStart - mesoEnd);
    67→    meso = 1 - t;
    68→  }
    69→
    70→  // MICRO opacity: 0 until mesoEnd, fade in through blend zone
    71→  if (zoom <= mesoEnd) {
    72→    micro = 0;
    73→  } else if (zoom < microStart) {
    74→    const t = (zoom - mesoEnd) / (microStart - mesoEnd);
    75→    micro = t;
    76→  } else {
    77→    micro = 1;
    78→  }
    79→
    80→  return { macro, meso, micro };
    81→}
    82→```
    83→
    84→### VERIFICATION: VERIFIED
    85→- LOD transitions work smoothly in visual testing
    86→- Both layers render simultaneously during blend zones
    87→- No "pop-in" effect at layer boundaries
    88→
    89→### CRITICAL MIGRATION NOTES
    90→1. Blend zone size (0.15) must match for smooth UX
    91→2. Both adjacent layers must render during transitions
    92→3. Opacity is applied via `transparent={opacity < 1}` on materials
