// In InfiniteCanvas.tsx - Animation loop reads from store directly
const animate = () => {
  // Read state from store (always current, no stale closures)
  const state = canvasStore.getState();
  const anim = state.viewport.animation;

  if (!anim.isAnimating) {
    return;
  }

  const elapsed = Date.now() - anim.startTime;
  const progress = Math.min(elapsed / anim.duration, 1);
  const easedProgress = Easing.quadOut(progress);

