  queryViewport(bounds: ViewportBounds): string[] {
    // O(log n + k) where k = result count
    const results = this.tree.search({
      minX: bounds.minX,
      minY: bounds.minY,
      maxX: bounds.maxX,
      maxY: bounds.maxY,
    });

    return results.map(item => item.id);
  }

  queryNearest(x: number, y: number, maxDistance?: number): SpatialQueryResult | null {
    // Expanding radius search
    let radius = 50;
    while (radius <= maxRadius && nearest === null) {
      const candidates = this.tree.search({
        minX: x - radius,
        minY: y - radius,
        maxX: x + radius,
        maxY: y + radius,
      });

      for (const item of candidates) {
        const dist = distanceToCenter(x, y, item);
        if (dist < minDist && dist <= maxRadius) {
          minDist = dist;
          nearest = { id: item.id, distance: dist };
        }
      }

      radius *= 2;
    }

    return nearest;
  }
}
```

### 5.2 EntityStore (TypedArray SoA Pattern)

**File:** `apps/canvas/src/entity-store/EntityStore.ts`

```typescript
/**
 * Memory layout for N tasks:
 * - startDay: Float32Array(N) - 4 bytes
 * - duration: Float32Array(N) - 4 bytes
 * - trainIndex: Uint16Array(N) - 2 bytes
 * - type: Uint8Array(N) - 1 byte
 * - color: Uint8Array(N) - 1 byte
 * - hasConflict: Uint8Array(N) - 1 byte
 * - predecessorIndex: Int32Array(N) - 4 bytes
 * Total: 17 bytes per task = ~1.7MB for 100k tasks
 */

export interface TaskArrays {
  startDay: Float32Array;
  duration: Float32Array;
  trainIndex: Uint16Array;
  type: Uint8Array;
  color: Uint8Array;
  hasConflict: Uint8Array;
  predecessorIndex: Int32Array;
}

class TaskCursorImpl implements TaskCursor {
  constructor(
    private readonly store: EntityStore,
    public readonly index: number
  ) {}

  get startDay(): number {
    return this.store.arrays.startDay[this.index];
  }

  // Computed properties for rendering (zero-allocation)
  get x(): number {
    return this.startDay * pxPerDay;
  }

  get y(): number {
    return -this.trainIndex * pxPerTrain - pxPerTrain / 2;
  }
}
